import json
import re

# Load all NPM packages with IsRelease=true
pkg_result = locals()['var_functions.query_db:102']
if isinstance(pkg_result, str) and pkg_result.endswith('.json'):
    with open(pkg_result, 'r') as f:
        release_packages = json.load(f)
else:
    release_packages = pkg_result

print('Total release packages:', len(release_packages))

# Load project mappings with stars
proj_result = locals()['var_functions.query_db:104']
if isinstance(proj_result, str) and proj_result.endswith('.json'):
    with open(proj_result, 'r') as f:
        project_mappings = json.load(f)
else:
    project_mappings = proj_result

print('Project mappings with stars:', len(project_mappings))

# Group release packages by name and find latest version (max ordinal)
from collections import defaultdict

package_versions = defaultdict(list)
for pkg in release_packages:
    try:
        name = pkg['Name']
        version = pkg['Version']
        version_info = json.loads(pkg.get('VersionInfo', '{}'))
        ordinal = version_info.get('Ordinal', 0)
        package_versions[name].append({
            'Version': version,
            'Ordinal': ordinal
        })
    except:
        continue

print('Unique packages:', len(package_versions))

# Get latest version for each package
latest_packages = {}
for name, versions in package_versions.items():
    if versions:
        latest = max(versions, key=lambda x: x['Ordinal'])
        latest_packages[name] = latest['Version']

print('Latest packages:', len(latest_packages))

# Create star lookup from project mappings
star_lookup = {}
for mapping in project_mappings:
    info = mapping.get('Project_Information', '')
    star_match = re.search(r'(\d+)\s+stars', info)
    if star_match:
        stars = int(star_match.group(1))
        key = (mapping['Name'], mapping['Version'])
        star_lookup[key] = stars

print('Star lookup entries:', len(star_lookup))

# Match latest packages with stars
matched = []
for name, version in latest_packages.items():
    key = (name, version)
    if key in star_lookup:
        matched.append({
            'Name': name,
            'Version': version,
            'Stars': star_lookup[key]
        })

print('Matched packages:', len(matched))

# Sort by stars and get top 5
top_5 = sorted(matched, key=lambda x: x['Stars'], reverse=True)[:5]

result = {
    'top_5_packages': top_5,
    'total_matched': len(matched)
}

print('Top 5 packages:')
for i, pkg in enumerate(top_5, 1):
    print(f"{i}. {pkg['Name']} (v{pkg['Version']}) - {pkg['Stars']} stars")

print('__RESULT__:')
print(json.dumps(result))

